select_uncorrelated_features <- function(dat, candidates, max_features = 3, max_abs_cor = 0.85) {
  selected <- character(0)
  candidates <- candidates[candidates %in% names(dat)]
  if (length(candidates) == 0) return(selected)
  for (fc in candidates) {
    if (length(selected) == 0) {
      selected <- c(selected, fc)
    } else {
      cors <- map_dbl(selected, ~abs(safe_cor(dat[[fc]], dat[[.x]], "pearson")))
      if (all(!is.finite(cors) | cors < max_abs_cor)) selected <- c(selected, fc)
    }
    if (length(selected) >= max_features) break
  }
  selected
}

