    if (includes_sex && "Sex" %in% names(model_dat_raw) && n_distinct(na.omit(model_dat_raw$Sex)) >= 2) "Sex" else character(0),
    if (includes_group && "Group" %in% names(model_dat_raw) && n_distinct(na.omit(model_dat_raw$Group)) >= 2) "Group" else character(0)
