  select(model_id, model_label, model_tier, tier_label, predictor_family, predictor_family_label, includes_sex, includes_group, tier_role)

tiered_predictions <- map_dfr(tiered_results, "predictions") %>%
  rename(model_id = Model) %>%
  left_join(tiered_model_metadata, by = "model_id") %>%
  mutate(
    model_tier = factor(model_tier, levels = c("A", "B", "C")),
    tier_label = factor(tier_label, levels = tier_definitions$tier_label)
  )

tiered_coefficients <- map_dfr(tiered_results, "coefficients") %>%
  rename(model_id = Model) %>%
  left_join(tiered_model_metadata, by = "model_id")

tiered_performance_base <- tiered_predictions %>%
  group_by(model_id, model_label, model_tier, tier_label, predictor_family, predictor_family_label, includes_sex, includes_group, Method) %>%
  group_modify(~prediction_metrics(.x$observed, .x$predicted)) %>%
  ungroup()

tiered_prediction_stats <- tiered_predictions %>%
  group_by(model_id, model_label, model_tier, tier_label, predictor_family, predictor_family_label, includes_sex, includes_group, Method) %>%
  group_modify(~correlation_test_stats(.x, "observed", "predicted", label = .y$model_id)) %>%
  ungroup() %>%
  select(-label) %>%
  left_join(
    tiered_performance_base %>%
      select(model_id, Method, rmse, mae, cv_r2_vs_mean),
    by = c("model_id", "Method")
  ) %>%
  mutate(
    Outcome = primary_outcome_label,
    BinLevel = bin_level,
    AnalysisUse = case_when(
      model_tier == "A" ~ "primary_behavior_only_prediction",
      model_tier == "B" ~ "sex_adjusted_sensitivity",
      model_tier == "C" ~ "group_informed_descriptive_upper_bound",
      TRUE ~ "tiered_prediction"
    ),
    Interpretation = case_when(
      model_tier == "A" ~ "Clean behavior-only early prediction; primary model tier.",
      model_tier == "B" ~ "Sensitivity model: behavior plus Sex, excluding Group.",
      model_tier == "C" ~ "Group-informed descriptive upper-bound; do not present as clean early behavioral prediction.",
      TRUE ~ NA_character_
    )
  ) %>%
  arrange(predictor_family, model_tier) %>%
  select(
    model_id, model_label, model_tier, tier_label, predictor_family, predictor_family_label,
    includes_sex, includes_group, n, pearson_r, spearman_rho, cv_r2_vs_mean, rmse, mae,
    pearson_p, spearman_p, Method, Outcome, BinLevel, AnalysisUse, Interpretation
  )

tiered_coefficient_stability <- if (nrow(tiered_coefficients) > 0) {
  n_folds_by_model <- tiered_predictions %>%
    filter(is.finite(predicted)) %>%
    count(model_id, name = "n_folds_with_prediction")
  tiered_coefficients %>%
    filter(term != "(Intercept)") %>%
    mutate(selected = is.finite(estimate) & abs(estimate) > 1e-8) %>%
    group_by(model_id, model_label, model_tier, tier_label, predictor_family, predictor_family_label, includes_sex, includes_group, term) %>%
    summarise(
      n_selected_folds = sum(selected, na.rm = TRUE),
      mean_coefficient = mean(estimate[selected], na.rm = TRUE),
      median_coefficient = median(estimate[selected], na.rm = TRUE),
      mean_abs_coefficient = mean(abs(estimate[selected]), na.rm = TRUE),
      .groups = "drop"
    ) %>%
    left_join(n_folds_by_model, by = "model_id") %>%
    mutate(
      selection_frequency = n_selected_folds / n_folds_with_prediction,
      mean_coefficient = if_else(is.nan(mean_coefficient), NA_real_, mean_coefficient),
      median_coefficient = if_else(is.nan(median_coefficient), NA_real_, median_coefficient),
      mean_abs_coefficient = if_else(is.nan(mean_abs_coefficient), NA_real_, mean_abs_coefficient)
    ) %>%
    arrange(model_id, desc(selection_frequency), desc(mean_abs_coefficient))
} else {
  tibble()
}

