# Sex-specific ladders are the biological companion to the pooled model above.
# They intentionally remove Sex as a covariate because each fit is within sex.
sex_model_specs <- map(model_specs, ~setdiff(.x, "Sex"))
sex_specific_results <- if ("Sex" %in% names(model_dat_raw) && n_distinct(na.omit(model_dat_raw$Sex)) >= 2) {
  valid_sexes <- model_dat_raw %>%
    filter(!is.na(Sex), is.finite(.data[[outcome_col]])) %>%
    count(Sex, name = "n_animals") %>%
    filter(n_animals >= min_n_for_sex_specific_models) %>%
    pull(Sex) %>%
    as.character()

  map(valid_sexes, function(sex_level) {
    sex_dat <- model_dat_raw %>% filter(as.character(Sex) == sex_level)
    fits <- imap(sex_model_specs, function(preds, model_name) {
      if (main_method == "elastic_net" && length(preds) > 0) {
        fit_predict_glmnet_loo(sex_dat, preds, model_name, alpha = elastic_net_alpha)
      } else {
        fit_predict_lm_loo(sex_dat, preds, model_name)
      }
    })
    list(
      predictions = map_dfr(fits, "predictions") %>% mutate(SexModel = sex_level, AnalysisStratum = paste0("sex_specific_", sex_level)),
      coefficients = map_dfr(fits, "coefficients") %>% mutate(SexModel = sex_level, AnalysisStratum = paste0("sex_specific_", sex_level))
    )
  })
} else {
  list()
}

sex_specific_predictions <- map_dfr(sex_specific_results, "predictions")
sex_specific_coefficients <- map_dfr(sex_specific_results, "coefficients")
sex_specific_performance <- if (nrow(sex_specific_predictions) > 0) {
  sex_specific_predictions %>%
    group_by(SexModel, AnalysisStratum, Model, Method) %>%
    group_modify(~prediction_metrics(.x$observed, .x$predicted)) %>%
    ungroup() %>%
    arrange(SexModel, desc(cv_r2_vs_mean), rmse) %>%
    mutate(
      Outcome = primary_outcome_label,
      BinLevel = bin_level,
      AnalysisUse = "sex_specific_systems_extension",
      DomainStep = classify_model_domain_step(Model),
      DisplayModel = recode(Model, !!!model_display_labels),
      UsesGroupAsPredictor = use_group_as_predictor,
      ReportingRole = case_when(
        Model == "Raw movement only" ~ "Sex-specific baseline biological signal",
        Model == "08b compact behavior" ~ "Sex-specific bridge to conservative 08b analysis",
        Model == "Full systems compact" ~ "Sex-specific systems-level extension",
        TRUE ~ "Sex-specific domain-ladder context"
      )
    )
} else {
  tibble()
}

